import axios from 'axios';
import { API_URL } from '../config/config';

// Create axios instance with the base API URL
const api = axios.create({
  baseURL: API_URL
});

// Add auth token to requests if available
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

/**
 * Forum service for handling forum posts, comments, likes, etc.
 */
const forumService = {
  /**
   * Get all forum posts with pagination
   * @param {number} page - Page number for pagination
   * @param {number} limit - Number of posts per page
   * @returns {Promise} - Promise with the posts data
   */
  getPosts: async (page = 1, limit = 10) => {
    try {
      const response = await api.get(`/forum/posts?page=${page}&limit=${limit}`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Get posts by category
   * @param {string} category - Category of posts
   * @param {number} page - Page number for pagination
   * @param {number} limit - Number of posts per page
   * @returns {Promise} - Promise with the filtered posts data
   */
  getPostsByCategory: async (category, page = 1, limit = 10) => {
    try {
      const response = await api.get(`/forum/posts/category/${category}?page=${page}&limit=${limit}`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Search posts by query
   * @param {string} query - Search query
   * @param {number} page - Page number for pagination
   * @param {number} limit - Number of posts per page
   * @returns {Promise} - Promise with the search results
   */
  searchPosts: async (query, page = 1, limit = 10) => {
    try {
      const response = await api.get(`/forum/posts/search?q=${encodeURIComponent(query)}&page=${page}&limit=${limit}`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Get a single post by ID
   * @param {string} postId - ID of the post to retrieve
   * @returns {Promise} - Promise with the post data
   */
  getPostById: async (postId) => {
    try {
      const response = await api.get(`/forum/posts/${postId}`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Create a new forum post
   * @param {Object} postData - Post data including title, content, etc.
   * @returns {Promise} - Promise with the created post data
   */
  createPost: async (postData) => {
    try {
      const formData = new FormData();
      
      // Add text fields
      Object.keys(postData).forEach(key => {
        if (key !== 'image') {
          formData.append(key, postData[key]);
        }
      });
      
      // Add image if exists
      if (postData.image) {
        formData.append('image', postData.image);
      }
      
      const response = await api.post('/forum/posts', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Update an existing forum post
   * @param {string} postId - ID of the post to update
   * @param {Object} postData - Updated post data
   * @returns {Promise} - Promise with the updated post data
   */
  updatePost: async (postId, postData) => {
    try {
      const formData = new FormData();
      
      // Add text fields
      Object.keys(postData).forEach(key => {
        if (key !== 'image') {
          formData.append(key, postData[key]);
        }
      });
      
      // Add image if exists
      if (postData.image) {
        formData.append('image', postData.image);
      }
      
      const response = await api.put(`/forum/posts/${postId}`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Delete a forum post
   * @param {string} postId - ID of the post to delete
   * @returns {Promise} - Promise with the deletion confirmation
   */
  deletePost: async (postId) => {
    try {
      const response = await api.delete(`/forum/posts/${postId}`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Like or unlike a post
   * @param {string} postId - ID of the post to like/unlike
   * @returns {Promise} - Promise with the updated like status
   */
  toggleLike: async (postId) => {
    try {
      const response = await api.post(`/forum/posts/${postId}/like`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Bookmark or unbookmark a post
   * @param {string} postId - ID of the post to bookmark/unbookmark
   * @returns {Promise} - Promise with the updated bookmark status
   */
  toggleBookmark: async (postId) => {
    try {
      const response = await api.post(`/forum/posts/${postId}/bookmark`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Get all comments for a post
   * @param {string} postId - ID of the post
   * @returns {Promise} - Promise with the comments data
   */
  getComments: async (postId) => {
    try {
      const response = await api.get(`/forum/posts/${postId}/comments`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Add a comment to a post
   * @param {string} postId - ID of the post
   * @param {Object} commentData - Comment data including content
   * @returns {Promise} - Promise with the created comment data
   */
  addComment: async (postId, commentData) => {
    try {
      const response = await api.post(`/forum/posts/${postId}/comments`, commentData);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Delete a comment
   * @param {string} postId - ID of the post
   * @param {string} commentId - ID of the comment to delete
   * @returns {Promise} - Promise with the deletion confirmation
   */
  deleteComment: async (postId, commentId) => {
    try {
      const response = await api.delete(`/forum/posts/${postId}/comments/${commentId}`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Get bookmarked posts for the current user
   * @param {number} page - Page number for pagination
   * @param {number} limit - Number of posts per page
   * @returns {Promise} - Promise with the bookmarked posts data
   */
  getBookmarkedPosts: async (page = 1, limit = 10) => {
    try {
      const response = await api.get(`/forum/bookmarks?page=${page}&limit=${limit}`);
      return response.data;
    } catch (error) {
      throw error;
    }
  },

  /**
   * Get posts created by the current user
   * @param {number} page - Page number for pagination
   * @param {number} limit - Number of posts per page
   * @returns {Promise} - Promise with the user's posts data
   */
  getUserPosts: async (page = 1, limit = 10) => {
    try {
      const response = await api.get(`/forum/user-posts?page=${page}&limit=${limit}`);
      return response.data;
    } catch (error) {
      throw error;
    }
  }
};

export default forumService;
